import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Validate input length to prevent buffer overflow
        if (input.length() > 10) {
            System.out.println("Input string is too long. Please enter a string with maximum 10 characters.");
            return;
        }

        // Allocate memory dynamically based on input length
        char[] buffer = new char[input.length()];
        input.getChars(0, input.length(), buffer, 0);

        System.out.println("Input: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
